import sys


def read_input():
    n, k = map(int, sys.stdin.readline().split())
    a = list(map(int, sys.stdin.readline().split()))
    return n, k, a


def solve(n, k, a):
    b = [0] * n
    for i in range(n):
        if i == 0:
            b[i] = k
        elif i == n - 1:
            b[i] = k
        else:
            b[i] = max(a[i] - a[i - 1], k)
    return b


def print_output(b):
    print(sum(b))
    print(' '.join(map(str, b)))


if __name__ == "__main__":
    n, k, a = read_input()
    b = solve(n, k, a)
    print_output(b)
